tools.handler:
var now = new Date();
var tz = args.timezone || 'UTC';
try {
  var opts = {timeZone: tz, year: 'numeric', month: 'long', day: 'numeric', weekday: 'long', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false, timeZoneName: 'long'};
  var formatted = now.toLocaleString('en-US', opts);
  var iso = now.toISOString();
  var parts = {iso: iso, formatted: formatted, timezone: tz, unix: Math.floor(now.getTime() / 1000)};
  return JSON.stringify(parts, null, 2);
} catch(e) {
  var iso = now.toISOString();
  return JSON.stringify({iso: iso, formatted: now.toUTCString(), timezone: 'UTC', unix: Math.floor(now.getTime() / 1000), note: 'Invalid timezone, showing UTC'}, null, 2);
}
